public class Box<T> {
    private T item;

    public void set(T item) {
        this.item = item;
    }

    public T get() {
        return item;
    }

    public static void main(String[] args) {
        Box<String> stringBox = new Box<>();
        stringBox.set("Hello Generics");
        System.out.println("String: " + stringBox.get());

        Box<Integer> intBox = new Box<>();
        intBox.set(123);
        System.out.println("Integer: " + intBox.get());
    }
}

public class GenericMethodTest {
    // Generic method printArray
    public static <E> void printArray(E[] inputArray) {
        for (E element : inputArray) {
            System.out.printf("%s ", element);
        }
        System.out.println();
    }

    public static void main(String args[]) {
        Integer[] intArray = { 1, 2, 3, 4, 5 };
        Double[] doubleArray = { 1.1, 2.2, 3.3 };
        Character[] charArray = { 'H', 'E', 'L', 'L', 'O' };

        System.out.println("Array intArray contains:");
        printArray(intArray); // pass an Integer array

        System.out.println("Array doubleArray contains:");
        printArray(doubleArray); // pass a Double array

        System.out.println("Array charArray contains:");
        printArray(charArray); // pass a Character array
    }
}

public class MaximumTest {
    // Limits T to types that implement Comparable<T>
    public static <T extends Comparable<T>> T maximum(T x, T y, T z) {
        T max = x;
        if (y.compareTo(max) > 0) {
            max = y;
        }
        if (z.compareTo(max) > 0) {
            max = z;
        }
        return max;
    }

    public static void main(String args[]) {
        System.out.printf("Max of %d, %d and %d is %d\n\n", 
            3, 4, 5, maximum(3, 4, 5));

        System.out.printf("Max of %.1f, %.1f and %.1f is %.1f\n\n",
            6.6, 8.8, 7.7, maximum(6.6, 8.8, 7.7));

        System.out.printf("Max of %s, %s and %s is %s\n",
            "pear", "apple", "orange", maximum("pear", "apple", "orange"));
    }
}

